3	use std::collections::{HashMap, HashSet};
4	
5	use mlpl_array::DenseArray;
6	
7	use crate::grad::OptimizerState;
8	
9	/// Variable bindings for evaluation.
10	#[derive(Clone, Debug, Default)]
11	pub struct Environment {
12	    vars: HashMap<String, DenseArray>,
13	    params: HashSet<String>,
14	    pub(crate) optim_state: OptimizerState,
15	}
16	
17	impl Environment {
18	    /// Create an empty environment.
19	    #[must_use]
20	    pub fn new() -> Self {
21	        Self::default()
