        }
        if !self.is(TokenKind::RBracket) {
            return Err(ParseError::UnclosedDelimiter {
                open: "[".into(),
                span: open_span,
            });
        }
        let close_span = self.tokens[self.pos].span;
        self.pos += 1;
        Ok(Expr::ArrayLit(
            elems,
            Span::new(open_span.start, close_span.end),
        ))
    }

    fn parse_repeat(&mut self) -> Result<Expr, ParseError> {
        let start = self.tokens[self.pos].span;
        self.pos += 1; // skip 'repeat'
        let count = self.parse_expr(0)?;
        if !self.is(TokenKind::LBrace) {
            return Err(ParseError::UnexpectedToken {
                found: describe_kind(&self.tokens[self.pos].kind),
                span: self.tokens[self.pos].span,
            });
        }
        let body = self.parse_brace_body()?;
        let end = self.tokens[self.pos - 1].span;
        Ok(Expr::Repeat {
            count: Box::new(count),
            body,
            span: Span::new(start.start, end.end),
        })
    }

    fn parse_brace_body(&mut self) -> Result<Vec<Expr>, ParseError> {
        let open = self.tokens[self.pos].span;
        self.pos += 1; // skip '{'
        self.skip_sep();
        let mut body = Vec::new();
        while self.pos < self.tokens.len()
            && !self.is(TokenKind::RBrace)
            && self.tokens[self.pos].kind != TokenKind::Eof
        {
            body.push(self.parse_statement()?);
            self.skip_sep();
        }
        if !self.is(TokenKind::RBrace) {
            return Err(ParseError::UnclosedDelimiter {
                open: "{".into(),
                span: open,
            });
        }
        self.pos += 1; // skip '}'
        Ok(body)
    }

    pub(crate) fn is(&self, kind: TokenKind) -> bool {
        self.pos < self.tokens.len()
            && std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(&kind)
    }

    pub(crate) fn skip_sep(&mut self) {
        while self.pos < self.tokens.len()
            && matches!(
                self.tokens[self.pos].kind,
                TokenKind::Newline | TokenKind::Semicolon
            )
        {
            self.pos += 1;
        }
    }
}

fn describe_kind(kind: &TokenKind) -> String {
    match kind {
        TokenKind::Eof => "end of input".into(),
        TokenKind::Newline => "newline".into(),
        TokenKind::IntLit(n) => format!("integer {n}"),
        TokenKind::FloatLit(n) => format!("float {n}"),
        TokenKind::StrLit(s) => format!("string \"{s}\""),
        TokenKind::Ident(s) => format!("identifier '{s}'"),
        TokenKind::LParen => "'('".into(),
        TokenKind::RParen => "')'".into(),
        TokenKind::LBracket => "'['".into(),
        TokenKind::RBracket => "']'".into(),
        TokenKind::LBrace => "'{'".into(),
        TokenKind::RBrace => "'}'".into(),
        TokenKind::Comma => "','".into(),
        TokenKind::Equals => "'='".into(),
        TokenKind::Semicolon => "';'".into(),
        TokenKind::Plus => "'+'".into(),
        TokenKind::Minus => "'-'".into(),
        TokenKind::Star => "'*'".into(),
        TokenKind::Slash => "'/'".into(),
        TokenKind::Repeat => "'repeat'".into(),
    }
}

//! Parser: transforms token stream into AST.

use mlpl_core::Span;

use crate::ast::{BinOpKind, Expr, TensorCtorKind};
use crate::error::ParseError;
use crate::token::{Token, TokenKind};

/// Parse a token stream into a list of expression statements.
pub fn parse(tokens: &[Token]) -> Result<Vec<Expr>, ParseError> {
    let mut p = Parser::new(tokens);
    let mut stmts = Vec::new();
    p.skip_sep();
    while p.pos < p.tokens.len() && p.tokens[p.pos].kind != TokenKind::Eof {
        stmts.push(p.parse_statement()?);
        p.skip_sep();
    }
    Ok(stmts)
}

pub(crate) struct Parser<'a> {
    pub(crate) tokens: &'a [Token],
    pub(crate) pos: usize,
}

impl<'a> Parser<'a> {
    pub(crate) fn new(tokens: &'a [Token]) -> Self {
        Self { tokens, pos: 0 }
    }

    /// Parse a single statement (assignment, repeat, or expression).
    fn parse_statement(&mut self) -> Result<Expr, ParseError> {
        if self.tokens[self.pos].kind == TokenKind::Repeat {
            return self.parse_repeat(false);
        }
        if self.tokens[self.pos].kind == TokenKind::Train {
            return self.parse_repeat(true);
        }
        if matches!(self.tokens[self.pos].kind, TokenKind::Ident(_))
            && self
                .tokens
                .get(self.pos + 1)
                .is_some_and(|t| t.kind == TokenKind::Equals)
        {
            let name_tok = &self.tokens[self.pos];
            let name = match &name_tok.kind {
                TokenKind::Ident(n) => n.clone(),
                _ => unreachable!(),
            };
            let start = name_tok.span;
            self.pos += 2;
            let value = self.parse_expr(0)?;
            let span = Span::new(start.start, value.span().end);
            return Ok(Expr::Assign {
                name,
                value: Box::new(value),
                span,
            });
        }
        self.parse_expr(0)
    }

    /// Parse an expression with precedence climbing (min_prec=0 for full expr).
    pub(crate) fn parse_expr(&mut self, min_prec: u8) -> Result<Expr, ParseError> {
        let mut lhs = self.parse_atom()?;
        loop {
            let Some((op, prec)) = self.tokens.get(self.pos).and_then(|t| match t.kind {
                TokenKind::Plus => Some((BinOpKind::Add, 1u8)),
                TokenKind::Minus => Some((BinOpKind::Sub, 1)),
                TokenKind::Star => Some((BinOpKind::Mul, 2)),
                TokenKind::Slash => Some((BinOpKind::Div, 2)),
                _ => None,
            }) else {
                break;
            };
            if prec < min_prec {
                break;
            }
            self.pos += 1;
            let rhs = self.parse_expr(prec + 1)?;
            let span = Span::new(lhs.span().start, rhs.span().end);
            lhs = Expr::BinOp {
                op,
                lhs: Box::new(lhs),
                rhs: Box::new(rhs),
                span,
            };
        }
        Ok(lhs)
    }

    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
        let tok = &self.tokens[self.pos];
        match &tok.kind {
            TokenKind::Minus => {
                let start = tok.span;
                self.pos += 1;
                let operand = self.parse_atom()?;
                let span = Span::new(start.start, operand.span().end);
                Ok(Expr::UnaryNeg {
                    operand: Box::new(operand),
                    span,
                })
            }
            TokenKind::IntLit(n) => {
                let e = Expr::IntLit(*n, tok.span);
                self.pos += 1;
                Ok(e)
            }
            TokenKind::FloatLit(f) => {
                let e = Expr::FloatLit(*f, tok.span);
                self.pos += 1;
                Ok(e)
            }
            TokenKind::StrLit(s) => {
                let e = Expr::StrLit(s.clone(), tok.span);
                self.pos += 1;
                Ok(e)
            }
            TokenKind::Ident(name) => {
                let name = name.clone();
                let start = tok.span;
                self.pos += 1;
                // Tensor constructor: `param[...]` or `tensor[...]`
                if self.is(TokenKind::LBracket) {
                    let ctor_kind = match name.as_str() {
                        "param" => Some(TensorCtorKind::Param),
                        "tensor" => Some(TensorCtorKind::Tensor),
                        _ => None,
                    };
                    if let Some(kind) = ctor_kind {
                        return self.parse_tensor_ctor(kind, start);
                    }
                }
                // Function call: ident '('
                if self.is(TokenKind::LParen) {
                    self.pos += 1; // skip '('
                    let mut args = Vec::new();
                    if !self.is(TokenKind::RParen) {
                        args.push(self.parse_expr(0)?);
                        while self.is(TokenKind::Comma) {
                            self.pos += 1;
                            args.push(self.parse_expr(0)?);
                        }
                    }
                    if !self.is(TokenKind::RParen) {
                        return Err(ParseError::UnclosedDelimiter {
                            open: "(".into(),
                            span: start,
                        });
                    }
                    let end = self.tokens[self.pos].span;
                    self.pos += 1;
                    Ok(Expr::FnCall {
                        name,
                        args,
                        span: Span::new(start.start, end.end),
                    })
                } else {
                    Ok(Expr::Ident(name, start))
                }
            }
            TokenKind::LBracket => self.parse_array_lit(),
            TokenKind::LParen => {
                let open = tok.span;
                self.pos += 1;
                let expr = self.parse_expr(0)?;
                if !self.is(TokenKind::RParen) {
                    return Err(ParseError::UnclosedDelimiter {
                        open: "(".into(),
                        span: open,
                    });
                }
                self.pos += 1;
                Ok(expr)
            }
            _ => Err(ParseError::UnexpectedToken {
                found: describe_kind(&tok.kind),
                span: tok.span,
            }),
        }
    }

    fn parse_tensor_ctor(&mut self, kind: TensorCtorKind, start: Span) -> Result<Expr, ParseError> {
        let open_span = self.tokens[self.pos].span;
        self.pos += 1; // skip '['
        let mut shape = Vec::new();
        if !self.is(TokenKind::RBracket) {
            shape.push(self.parse_expr(0)?);
            while self.is(TokenKind::Comma) {
                self.pos += 1;
                shape.push(self.parse_expr(0)?);
            }
        }
        if !self.is(TokenKind::RBracket) {
            return Err(ParseError::UnclosedDelimiter {
                open: "[".into(),
                span: open_span,
            });
        }
        let close_span = self.tokens[self.pos].span;
        self.pos += 1;
        Ok(Expr::TensorCtor {
            kind,
            shape,
            span: Span::new(start.start, close_span.end),
        })
    }

    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
        let open_span = self.tokens[self.pos].span;
        self.pos += 1;
        let mut elems = Vec::new();
        if !self.is(TokenKind::RBracket) {
            elems.push(self.parse_expr(0)?);
            while self.is(TokenKind::Comma) {
                self.pos += 1;
                elems.push(self.parse_expr(0)?);
            }
        }
        if !self.is(TokenKind::RBracket) {
            return Err(ParseError::UnclosedDelimiter {
                open: "[".into(),
                span: open_span,
            });
        }
        let close_span = self.tokens[self.pos].span;
        self.pos += 1;
        Ok(Expr::ArrayLit(
            elems,
            Span::new(open_span.start, close_span.end),
        ))
    }

    fn parse_repeat(&mut self, is_train: bool) -> Result<Expr, ParseError> {
        let start = self.tokens[self.pos].span;
        self.pos += 1; // skip 'repeat' or 'train'
        let count = self.parse_expr(0)?;
        if !self.is(TokenKind::LBrace) {
            return Err(ParseError::UnexpectedToken {
                found: describe_kind(&self.tokens[self.pos].kind),
                span: self.tokens[self.pos].span,
            });
        }
        let body = self.parse_brace_body()?;
        let end = self.tokens[self.pos - 1].span;
        let span = Span::new(start.start, end.end);
        let count = Box::new(count);
        Ok(if is_train {
            Expr::Train { count, body, span }
        } else {
            Expr::Repeat { count, body, span }
        })
    }

    fn parse_brace_body(&mut self) -> Result<Vec<Expr>, ParseError> {
        let open = self.tokens[self.pos].span;
        self.pos += 1; // skip '{'
        self.skip_sep();
        let mut body = Vec::new();
        while self.pos < self.tokens.len()
            && !self.is(TokenKind::RBrace)
            && self.tokens[self.pos].kind != TokenKind::Eof
        {
            body.push(self.parse_statement()?);
            self.skip_sep();
        }
        if !self.is(TokenKind::RBrace) {
            return Err(ParseError::UnclosedDelimiter {
                open: "{".into(),
                span: open,
            });
        }
        self.pos += 1; // skip '}'
        Ok(body)
    }

    pub(crate) fn is(&self, kind: TokenKind) -> bool {
        self.pos < self.tokens.len()
            && std::mem::discriminant(&self.tokens[self.pos].kind) == std::mem::discriminant(&kind)
    }

    pub(crate) fn skip_sep(&mut self) {
        while self.pos < self.tokens.len()
            && matches!(
                self.tokens[self.pos].kind,
                TokenKind::Newline | TokenKind::Semicolon
            )
        {
            self.pos += 1;
        }
    }
}

fn describe_kind(kind: &TokenKind) -> String {
    match kind {
        TokenKind::Eof => "end of input".into(),
        TokenKind::Newline => "newline".into(),
        TokenKind::IntLit(n) => format!("integer {n}"),
        TokenKind::FloatLit(n) => format!("float {n}"),
        TokenKind::StrLit(s) => format!("string \"{s}\""),
        TokenKind::Ident(s) => format!("identifier '{s}'"),
        TokenKind::LParen => "'('".into(),
        TokenKind::RParen => "')'".into(),
        TokenKind::LBracket => "'['".into(),
        TokenKind::RBracket => "']'".into(),
        TokenKind::LBrace => "'{'".into(),
        TokenKind::RBrace => "'}'".into(),
        TokenKind::Comma => "','".into(),
        TokenKind::Equals => "'='".into(),
        TokenKind::Semicolon => "';'".into(),
        TokenKind::Plus => "'+'".into(),
        TokenKind::Minus => "'-'".into(),
        TokenKind::Star => "'*'".into(),
        TokenKind::Slash => "'/'".into(),
        TokenKind::Repeat => "'repeat'".into(),
    }
}

//! AST-walking evaluator.

use mlpl_array::{DenseArray, Shape};
use mlpl_autograd::{Tape, Tensor};
use mlpl_parser::{Expr, TensorCtorKind};
use mlpl_trace::{Trace, TraceEvent, TraceValue};

use crate::env::Environment;
use crate::error::EvalError;
use crate::eval_ops::{eval_analysis_helper, eval_array_lit, eval_binop, eval_fncall, eval_svg};
use crate::value::Value;

/// Evaluate a program (list of statements). Returns the last result as an array.
///
/// If the final value is a string, returns `EvalError::ExpectedArray`.
/// Use `eval_program_value` to handle both arrays and strings.
pub fn eval_program(stmts: &[Expr], env: &mut Environment) -> Result<DenseArray, EvalError> {
    eval_program_value(stmts, env)?.into_array()
}

/// Evaluate a program and return the final value (array or string).
pub fn eval_program_value(stmts: &[Expr], env: &mut Environment) -> Result<Value, EvalError> {
    run_program(stmts, env, None)
}

/// Evaluate a program with tracing enabled. Returns the final array.
pub fn eval_program_traced(
    stmts: &[Expr],
    env: &mut Environment,
    trace: &mut Trace,
) -> Result<DenseArray, EvalError> {
    run_program(stmts, env, Some(trace))?.into_array()
}

fn run_program(
    stmts: &[Expr],
    env: &mut Environment,
    mut trace: Option<&mut Trace>,
) -> Result<Value, EvalError> {
    if stmts.is_empty() {
        return Err(EvalError::EmptyInput);
    }
    let mut result = None;
    for stmt in stmts {
        result = Some(eval_expr(stmt, env, &mut trace)?);
    }
    result.ok_or(EvalError::EmptyInput)
}

pub(crate) fn eval_expr(
    expr: &Expr,
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<Value, EvalError> {
    if let Expr::StrLit(s, _) = expr {
        return Ok(Value::Str(s.clone()));
    }
    if let Expr::FnCall { name, args, .. } = expr
        && name == "svg"
    {
        return eval_svg(args, env, trace).map(Value::Str);
    }
    if let Expr::FnCall { name, args, span } = expr
        && name == "grad"
    {
        let result = crate::grad::eval_grad(args, env)?;
        if let Some(t) = trace.as_mut() {
            let seq = t.events().len() as u64;
            t.push(TraceEvent {
                seq,
                op: "grad".into(),
                span: *span,
                inputs: vec![],
                output: TraceValue::from_array(&result),
            });
        }
        return Ok(Value::Array(result));
    }
    if let Expr::FnCall { name, args, span } = expr
        && (name == "momentum_sgd" || name == "adam")
    {
        let result = if name == "momentum_sgd" {
            crate::grad::eval_momentum_sgd(args, env)?
        } else {
            crate::grad::eval_adam(args, env)?
        };
        if let Some(t) = trace.as_mut() {
            let seq = t.events().len() as u64;
            t.push(TraceEvent {
                seq,
                op: name.clone(),
                span: *span,
                inputs: vec![],
                output: TraceValue::from_array(&result),
            });
        }
        return Ok(Value::Array(result));
    }
    if let Expr::FnCall { name, args, .. } = expr
        && let Some(result) = eval_analysis_helper(name, args, env, trace)
    {
        return result.map(Value::Str);
    }
    let (op_name, inputs, result) = match expr {
        Expr::IntLit(n, _) => ("literal", vec![], DenseArray::from_scalar(*n as f64)),
        Expr::FloatLit(f, _) => ("literal", vec![], DenseArray::from_scalar(*f)),
        Expr::StrLit(_, _) => unreachable!(),
        Expr::Ident(name, _) => {
            let r = env
                .get(name)
                .cloned()
                .ok_or_else(|| EvalError::UndefinedVariable(name.clone()))?;
            ("ident", vec![], r)
        }
        Expr::ArrayLit(elems, _) => ("array_lit", vec![], eval_array_lit(elems, env, trace)?),
        Expr::UnaryNeg { operand, .. } => {
            let val = eval_expr(operand, env, trace)?.into_array()?;
            let r = DenseArray::from_scalar(-1.0).apply_binop(&val, |a, b| a * b)?;
            ("negate", vec![TraceValue::from_array(&val)], r)
        }
        Expr::Assign { name, value, .. } => {
            let is_param_ctor = matches!(
                value.as_ref(),
                Expr::TensorCtor {
                    kind: TensorCtorKind::Param,
                    ..
                }
            );
            let val = eval_expr(value, env, trace)?.into_array()?;
            env.set(name.clone(), val.clone());
            if is_param_ctor {
                env.mark_param(name);
            }
            ("assign", vec![TraceValue::from_array(&val)], val)
        }
        Expr::BinOp { op, lhs, rhs, .. } => eval_binop(op, lhs, rhs, env, trace)?,
        Expr::FnCall { name, args, .. } => eval_fncall(name, args, env, trace)?,
        Expr::TensorCtor { kind, shape, .. } => eval_tensor_ctor(*kind, shape, env, trace)?,
        Expr::Repeat { count, body, .. } => eval_repeat(count, body, env, trace)?,
    };
    if let Some(t) = trace.as_mut() {
        let seq = t.events().len() as u64;
        t.push(TraceEvent {
            seq,
            op: op_name.into(),
            span: expr.span(),
            inputs,
            output: TraceValue::from_array(&result),
        });
    }
    Ok(Value::Array(result))
}

fn eval_tensor_ctor(
    kind: TensorCtorKind,
    shape: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
    let mut dims = Vec::with_capacity(shape.len());
    for dim_expr in shape {
        let arr = eval_expr(dim_expr, env, trace)?.into_array()?;
        if arr.rank() != 0 {
            return Err(EvalError::InvalidShapeDim);
        }
        let v = arr.data()[0];
        if v < 0.0 || v.fract() != 0.0 {
            return Err(EvalError::InvalidShapeDim);
        }
        dims.push(v as usize);
    }
    let zeros = DenseArray::zeros(Shape::new(dims));
    // Construct an autograd Tensor on a fresh tape. Step 005 will
    // route this through a tape stored in the environment so that
    // operations on the resulting array are recorded; for now we
    // simply return the underlying zero-initialized array.
    let tape = Tape::new();
    let _tensor = match kind {
        TensorCtorKind::Param => Tensor::param(tape, zeros.clone()),
        TensorCtorKind::Tensor => Tensor::leaf(tape, zeros.clone(), false),
    };
    let op_name = match kind {
        TensorCtorKind::Param => "param_ctor",
        TensorCtorKind::Tensor => "tensor_ctor",
    };
    Ok((op_name, vec![], zeros))
}

fn eval_repeat(
    count: &Expr,
    body: &[Expr],
    env: &mut Environment,
    trace: &mut Option<&mut Trace>,
) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
    let n_arr = eval_expr(count, env, trace)?.into_array()?;
    if n_arr.rank() != 0 {
        return Err(EvalError::InvalidRepeatCount);
    }
    let n = n_arr.data()[0] as usize;
    let mut r = DenseArray::from_scalar(0.0);
    for _ in 0..n {
        for stmt in body {
            r = eval_expr(stmt, env, trace)?.into_array()?;
        }
    }
    Ok(("repeat", vec![], r))
}

